{
  "source": "locked_product_design_baseline",
  "project_name": "Linear Fronting Showcase",
  "baseline_locked_at": "2026-06-06T17:05:27.366Z",
  "requirements": {
    "id": "req-ebad5c5b-55b0-4a51-ba66-d684115622f6",
    "title": "Drafted Product Requirements",
    "data": {
      "auth": {
        "purpose_binding": true,
        "scoped_authority": true,
        "delegation_tokens": true
      },
      "audit": {
        "durable": true,
        "searchable": true
      },
      "scale": {
        "shape_preference": "production_single_service",
        "high_availability": false
      },
      "trust": {
        "mode": "signed",
        "checkpoints": false
      },
      "system": {
        "name": "linear-fronting-showcase",
        "domain": "linear",
        "deployment_intent": "public_http_service"
      },
      "lineage": {
        "task_id": true,
        "invocation_id": true,
        "client_reference_id": true,
        "parent_invocation_id": true
      },
      "transports": {
        "grpc": false,
        "http": true,
        "stdio": false
      },
      "permissions": {
        "preflight_discovery": true,
        "restricted_vs_denied": true
      },
      "risk_profile": {},
      "business_constraints": {
        "assistant_drafted_requirements_count": 10,
        "assistant_drafted_requirements_summary": "Expose a governed Linear capability surface instead of raw workspace tools: The product shall provide an ANIP fronting service for Linear that exposes only organization-approved product-work capabilities for issue discovery, issue preparation, comment preparation, status transition requests, and cycle move requests. The service shall not expose raw Linear workspace tools or arbitrary GraphQL operations to agents.\nSupport bounded, team-scoped issue context search: The product shall support read-only search of Linear issue context using a required team key and query, with bounded result limits and actor-visible summaries only. Search behavior shall remain constrained to approved team scope and must return clarification_required when required context such as team scope is missing or ambiguous.\nRequire preview-first behavior for issue and comment creation flows: The product shall prepare issue creation previews and issue comment previews without creating or posting anything directly. Issue preparation shall collect required team, title, and description inputs and may include governed metadata such as project, labels, and other approved optional fields. Comment preparation shall collect issue, purpose, and bounded context and return a preview suitable for review before posting.\nGate all write-adjacent Linear actions behind approval boundaries: The product shall treat issue creation preparation, comment preparation, status transition requests, and cycle move requests as approval-gated flows. For each of these actions, the service shall stop at a preview or request artifact and require explicit approval before any downstream mutation is allowed to proceed.\nGovern status transition requests with reason capture and restricted-state controls: The product shall support governed status transition requests for a specified issue and target status, with a required business reason. The service shall return clarification_required when issue or target status context is missing or ambiguous, and it shall enforce explicit grant requirements for restricted workflow states rather than allowing direct workflow bypass.\nGovern cycle move requests and restrict cross-team moves: The product shall support governed requests to move an issue into a target cycle using a required issue reference, target cycle, and business reason. The service shall stop for approval before any move occurs and shall require explicit grant for cross-team moves.\nReturn clarification_required when required operational context is missing: The product shall use explicit clarification semantics when required context is absent or ambiguous. At minimum, missing or unclear team, issue, target status, or target container context shall not be guessed and shall instead produce clarification_required so the caller can supply the missing information.\nPrevent hidden-team access, raw export, and unapproved mutation paths: The product shall deny private team exfiltration, hidden team access, raw workspace export, arbitrary backend execution, workflow bypass, and unapproved mutation attempts. Governed provider controls may be supported only when they remain bounded and cannot override team scope, approval policy, or export restrictions.\nApply actor-aware visibility and team allowlist controls across all capabilities: The product shall enforce actor-aware visibility and team allowlists across search, preparation, and request flows. Responses shall expose only the level of detail appropriate for the caller's allowed team scope and governance posture.\nPreserve approval records and auditability for governed Linear actions: The product shall maintain approval records and audit evidence for governed actions so reviewers can understand what was requested, why it was requested, what policy boundary applied, and whether the action was allowed, restricted, denied, or stopped for approval."
      }
    }
  },
  "scenarios": [
    {
      "id": "scn-11a69238-3caf-4549-b8cc-08616adb569a",
      "title": "Request moving an issue into a cycle and stop for approval",
      "data": {
        "scenario": {
          "name": "request-moving-an-issue-into-a-cycle-and-stop-for-approval",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source explicitly defines cycle move as a governed request with approval gating and explicit grant requirements for cross-team moves.",
            "capability": "linear.cycle_move.request",
            "confidence": "high",
            "time_scope": "During sprint or cycle planning and reprioritization",
            "actor_context": "Linear requester attempting to reassign planned work into a cycle",
            "business_scope": "Governed cycle assignment changes with approval and cross-team controls"
          },
          "category": "cross_service",
          "narrative": "A requester wants to move a Linear issue into a target cycle. The service validates the issue, target cycle, and reason, prepares a governed move request, and stops for approval. If the move crosses team boundaries without explicit grant, the service returns a restricted outcome.",
          "expected_behavior": [
            "Require issue, target cycle, and business reason.",
            "Detect and restrict cross-team moves without explicit grant.",
            "Prepare a move request rather than changing the issue directly.",
            "Stop for approval before execution.",
            "Preserve clear requester feedback when the move is restricted."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Clarification-required handling for incomplete move requests.",
            "Policy enforcement for cross-team movement restrictions.",
            "Approval-gated request semantics for cycle reassignment.",
            "Auditability of move requests, approvals, and denials."
          ],
          "participating_services": [
            "Linear Governance Service",
            "Linear GraphQL API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-5b3bd924-cb78-46ec-968f-6a4481561bc3",
      "title": "Show different outcomes for the same workflow-change ask based on actor authority",
      "data": {
        "scenario": {
          "name": "show-different-outcomes-for-the-same-workflow-change-ask-based-on-actor-authority",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The in-flight context and policy semantics strongly imply actor-differentiated behavior, though the brief is stronger on policy posture than on a single canonical example flow.",
            "capability": "linear.status_transition.request",
            "confidence": "medium",
            "time_scope": "Any time a workflow change is requested",
            "actor_context": "Comparison between a permitted requester and a narrower team-scoped actor",
            "business_scope": "Actor-aware governance for Linear workflow changes"
          },
          "category": "cross_service",
          "narrative": "Two actors request the same status transition or cycle move for a Linear issue. A permitted requester receives a prepared request that stops for approval, while a narrower actor receives a restricted, masked, or denied outcome because of team scope or workflow restrictions.",
          "expected_behavior": [
            "Apply actor-aware visibility and authority checks to the same underlying request.",
            "Allow a permitted actor to prepare a request but still stop for approval.",
            "Restrict or deny the same request for a narrower actor when policy requires it.",
            "Make the reason for the different outcomes explicit."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Actor-aware policy evaluation across the same capability.",
            "Explicit governed outcomes such as approval_required, restricted, or denied.",
            "Audit support showing why each actor received a different result."
          ],
          "participating_services": [
            "Linear Governance Service",
            "Linear GraphQL API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-0f99fe60-75e2-4bf9-8614-70d273389e91",
      "title": "Search bounded Linear issue context within a team",
      "data": {
        "scenario": {
          "name": "search-bounded-linear-issue-context-within-a-team",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the search capability, team scoping rules, result limits, and the stated purpose of hiding raw workspace access behind governed product-work capabilities.",
            "capability": "linear.issue.search_context",
            "confidence": "high",
            "time_scope": "On demand during issue triage or planning",
            "actor_context": "Team-scoped member searching within an allowed Linear team",
            "business_scope": "Linear issue discovery with governed visibility and bounded results"
          },
          "category": "safety",
          "narrative": "A user needs issue context in Linear and asks the fronting service to search within a specific team. The service returns bounded issue, project, or cycle summaries that match the query, while enforcing team scope and result limits.",
          "expected_behavior": [
            "Require team_key and query before execution.",
            "Constrain search to the allowed team scope.",
            "Return bounded results with a governed limit.",
            "Expose summaries appropriate to the actor rather than raw backend data.",
            "Deny hidden team access or raw export behavior."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Clarification-required handling for missing team or query context.",
            "Policy enforcement for team allowlists and actor-aware visibility.",
            "Bounded execution against the native Linear GraphQL backend.",
            "Auditability of search requests and governed result shaping."
          ],
          "participating_services": [
            "Linear Governance Service",
            "Linear GraphQL API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-2b991573-a0a9-4d77-9371-b4240fa3503b",
      "title": "Prepare an issue comment from bounded context before posting",
      "data": {
        "scenario": {
          "name": "prepare-an-issue-comment-from-bounded-context-before-posting",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The comment preparation capability is explicitly defined as preview-only and intended for review or incident context without posting.",
            "capability": "linear.comment.prepare",
            "confidence": "high",
            "time_scope": "During incident follow-up, review, or status communication",
            "actor_context": "Linear requester preparing communication on an existing issue",
            "business_scope": "Governed issue comment preparation with approval stop"
          },
          "category": "safety",
          "narrative": "A requester wants to add a comment to a Linear issue based on review or incident context. The service validates the issue reference and comment purpose, prepares a governed comment preview from the supplied context, and stops before any comment is posted.",
          "expected_behavior": [
            "Require issue reference, comment purpose, and bounded context.",
            "Prepare a comment preview rather than posting directly.",
            "Preserve the distinction between preparation and execution.",
            "Stop for approval before any comment mutation occurs."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Clarification handling for incomplete comment requests.",
            "Preview-only comment preparation semantics.",
            "Approval gating and audit support for proposed issue communications.",
            "Bounded backend execution without exposing raw comment tooling."
          ],
          "participating_services": [
            "Linear Governance Service",
            "Linear GraphQL API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-fc379c1d-2bef-4132-bddc-6aaec70f3d7f",
      "title": "Request a governed issue status transition and stop for approval",
      "data": {
        "scenario": {
          "name": "request-a-governed-issue-status-transition-and-stop-for-approval",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source explicitly defines status transition as a governed request, approval-gated, with restricted workflow states requiring explicit grant.",
            "capability": "linear.status_transition.request",
            "confidence": "high",
            "time_scope": "During triage, execution, or escalation",
            "actor_context": "Linear requester or team-scoped member attempting a workflow change",
            "business_scope": "Governed workflow state changes with approval and restriction controls"
          },
          "category": "cross_service",
          "narrative": "A requester wants to change the workflow status of a Linear issue. The service validates the issue, target status, and business reason, prepares a governed transition request, and stops for approval. If the target status is restricted for the actor, the service returns a restricted outcome instead of proceeding.",
          "expected_behavior": [
            "Require issue, target status, and business reason.",
            "Check whether the actor is allowed to request the target workflow state.",
            "Prepare a governed transition request rather than updating the issue directly.",
            "Stop for approval before execution.",
            "Return restricted or denied outcomes for disallowed workflow changes."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Clarification-required handling for incomplete workflow requests.",
            "Policy enforcement for restricted workflow states and actor authority.",
            "Approval-gated request semantics with explicit stop conditions.",
            "Audit records for requested status changes and policy decisions."
          ],
          "participating_services": [
            "Linear Governance Service",
            "Linear GraphQL API adapter"
          ]
        }
      }
    },
    {
      "id": "scn-512b750d-e493-4d40-8419-d9adeede798e",
      "title": "Prepare a new Linear issue for approval before creation",
      "data": {
        "scenario": {
          "name": "prepare-a-new-linear-issue-for-approval-before-creation",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The brief explicitly defines issue preparation as preview-only, mapped to creation inputs, and approval-required before creation.",
            "capability": "linear.issue.prepare",
            "confidence": "high",
            "time_scope": "During intake, triage, or work planning",
            "actor_context": "Linear requester preparing work for a team",
            "business_scope": "Governed issue creation preparation with approval stop"
          },
          "category": "orchestration",
          "narrative": "A requester wants to create a Linear issue but the system only prepares a governed preview. The service validates the team and proposed issue content, assembles the issue draft with optional project and labels, and stops at the approval boundary before any creation occurs.",
          "expected_behavior": [
            "Require team, title, and description before preparing the issue.",
            "Allow optional governed issue metadata such as project or labels when provided.",
            "Return a preview rather than creating the issue.",
            "Make the approval stop explicit to the requester.",
            "Prevent unapproved issue creation."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Preview-only contract semantics for issue creation preparation.",
            "Approval-gated flow control before any write occurs.",
            "Actor-aware policy enforcement and approval record support.",
            "Audit trail for who prepared the issue and why it stopped."
          ],
          "participating_services": [
            "Linear Governance Service",
            "Linear GraphQL API adapter"
          ]
        }
      }
    }
  ],
  "service_design": {
    "id": "shape-00db15ab-9cec-4ec5-9194-52ea9a78d2ea",
    "title": "Assistant-Drafted Service Shape",
    "data": {
      "shape": {
        "id": "shape-39713587-dd37-4c10-b9b9-8c1d95eef5da",
        "name": "Linear Fronting Showcase",
        "type": "single_service",
        "notes": [
          "Assistant-derived first pass. Review service boundaries before locking Developer Design.",
          "Service topology was constrained by explicit topology preference or preserved source service boundaries."
        ],
        "services": [
          {
            "id": "linear-governance-service",
            "name": "Linear Governance",
            "role": "implementation service",
            "capabilities": [
              "linear.issue.search_context",
              "linear.issue.prepare",
              "linear.comment.prepare",
              "linear.status_transition.request",
              "linear.cycle_move.request"
            ],
            "owns_concepts": [],
            "responsibilities": [
              "Own a reviewed portion of the bounded workflow, policy checks, clarification stops, and governed response contract."
            ]
          }
        ],
        "coordination": [],
        "domain_concepts": []
      }
    }
  }
}

